  // ---- Money Psychology ----
  "psy-biases": [
    { id: "psy-bia-x1", tier: "easy", type: "mc", prompt: "Loss aversion means people...",
      choices: [{ id: "a", label: "Feel losses more strongly than equal gains" }, { id: "b", label: "Love losing money" }, { id: "c", label: "Ignore losses" }, { id: "d", label: "Prefer risk" }],
      answer: "a", explanation: "Loss aversion is the tendency for a loss to hurt more than a same sized gain feels good." },
    { id: "psy-bia-x2", tier: "medium", type: "mc", prompt: "The sunk cost fallacy leads people to...",
      choices: [{ id: "a", label: "Keep going because of money already spent" }, { id: "b", label: "Ignore the past entirely" }, { id: "c", label: "Always quit early" }, { id: "d", label: "Save more" }],
      answer: "a", explanation: "The sunk cost fallacy keeps people committed to bad choices because of unrecoverable past investment, instead of looking forward." },
    { id: "psy-bia-x3", tier: "medium", type: "mc", prompt: "How does a crossed out 'original' price use anchoring?",
      choices: [{ id: "a", label: "The high number makes the sale price feel like a better deal" }, { id: "b", label: "It hides the price" }, { id: "c", label: "It raises the real cost" }, { id: "d", label: "It has no effect" }],
      answer: "a", explanation: "The high anchor shifts your sense of a fair price, so the lower price seems like a bargain even if it is the normal price." },
    { id: "psy-bia-x4", tier: "hard", type: "mc", prompt: "Why is automating savings an effective defense against biases?",
      choices: [{ id: "a", label: "It removes in the moment decisions where biases take over" }, { id: "b", label: "It earns guaranteed returns" }, { id: "c", label: "It avoids taxes" }, { id: "d", label: "It has no effect" }],
      answer: "a", explanation: "Automation makes the good choice the default, so you do not have to fight present bias or temptation each time." },
  ],
